SELECT n.*
FROM notifications n
INNER JOIN external_data_mapping edm ON n.track_id = edm.track_id;

SELECT SUM(streams) AS total_streams
FROM tracks
WHERE genre = 'Indie Pop';

SELECT track_name, artist_names, peak_rank
FROM tracks
WHERE weeks_on_chart > 15 AND peak_rank > 5;

SELECT genre, COUNT(*) as track_count
FROM tracks
GROUP BY genre;

SELECT DISTINCT track_name
FROM tracks
WHERE weeks_on_chart > 10 AND streams > 100000 AND peak_rank > 20;

SELECT track_name, artist_names, genre, peak_rank
FROM tracks
WHERE genre = 'Pop' AND peak_rank > (
    SELECT AVG(peak_rank)
    FROM tracks
);
